```python
#coding=utf8
import itchat

friendName = u'LittleCoder'

@itchat.msg_register(itchat.content.CARD)
def reply(msg):
    if msg.fromUserName == itchat.originInstance.storageClass.userName:
        friend = itchat.search_friends(nickName=friendName)
        if friend:
            friend = friend[0]
        else:
            print('No friend name %s' % friendName)
        r = friend.send_raw_msg(msg.msgType, msg.content)
        if r:
            print('Name card sent')
        else:
            print(r)
    else:
        print('Send a name card to someone to use this script')

itchat.auto_login(True)
itchat.run()
```

其中msgType是固定的，content可以存储下来多次使用。

```
#!/usr/bin/python

import chess.pgn
import sys

SKIP_PLIES = 40
FILENAME = sys.argv[1]

pgn = open(FILENAME)
out = chess.pgn.FileExporter(sys.stdout)

def skip_nodes(game, plies):
    node = game
    for _ in range(plies):
        if node.variations:
            node = node.variations[0]
        else:
            return
    return node

while True:
    game = chess.pgn.read_game(pgn)
    if game is None:
        break

    node = skip_nodes(game, SKIP_PLIES)
    if node:
        node.accept_subgame(out)
```

