I solved this problem by creating a directive local to stTable and broadcasting the event. 

**View**
```
<table st-pipe="productsTableCtrl.getTableData" 
st-table="productsTableCtrl.tableData" refresh-table>
```

**Controller**
`$scope.$broadcast('refreshProducts');`

**Directive**
```
app.directive("refreshTable", function(){
    return {
        require:'stTable',
        restrict: "A",
        link:function(scope,elem,attr,table){
            scope.$on("refreshProducts", function() {
                table.pipe(table.tableState());
            });
    }
}});
```

